function fireConfetti(colors=[TEAL,"#fff",GOLD]){
  const c=document.createElement("canvas");
  c.style.cssText="position:fixed;inset:0;width:100%;height:100%;z-index:9999;pointer-events:none";
  document.body.appendChild(c);const ctx=c.getContext("2d");c.width=window.innerWidth;c.height=window.innerHeight;
  const pp=Array.from({length:80},()=>({x:Math.random()*c.width,y:-10,vx:(Math.random()-.5)*6,vy:Math.random()*4+2,
    color:colors[Math.floor(Math.random()*colors.length)],size:Math.random()*8+4,rot:Math.random()*360,vrot:(Math.random()-.5)*10,alpha:1}));
  let fr=0;const tick=()=>{ctx.clearRect(0,0,c.width,c.height);pp.forEach(p=>{p.x+=p.vx;p.y+=p.vy;p.rot+=p.vrot;p.vy+=.1;p.alpha=Math.max(0,1-fr/90);
    ctx.save();ctx.globalAlpha=p.alpha;ctx.translate(p.x,p.y);ctx.rotate(p.rot*Math.PI/180);ctx.fillStyle=p.color;ctx.fillRect(-p.size/2,-p.size/2,p.size,p.size/2);ctx.restore();});
    if(++fr<100)requestAnimationFrame(tick);else c.remove();};requestAnimationFrame(tick);
}

// ── K-коэффициент по типу пряжи ───────────────────────────────────────────────
const K_BY_CATEGORY={
  "Кружевная":1.2,"Тонкая":1.3,"Спорт":1.4,"DK":1.5,
  "Ворстед":1.55,"Аран":1.65,"Толстая":1.75,"Супертолстая":1.9,
};
const PATTERN_FACTORS=[
  {label:"Лицевая гладь",value:1.0},{label:"Резинка 1×1",value:1.15},
  {label:"Резинка 2×2",value:1.2},{label:"Жемчужная",value:1.1},
  {label:"Косы",value:1.35},{label:"Ажур",value:0.9},{label:"Жаккард",value:1.3},
];

// ── Центральная функция расчёта пряжи ────────────────────────────────────────
function calcYarn({itemW,itemH,margin,sampleW,sampleH,sampleG,stitches,rows,sampleSize,metersPerHundred,patternFactor,kFactor}){
  const areaItem=itemW*itemH;
  let grams=0,meters=0;
  if(sampleG>0){
    // Режим 1: через вес образца (точный)
    const areaSample=(sampleW||10)*(sampleH||10);
    grams=(sampleG/areaSample)*areaItem;
    if(metersPerHundred>0)meters=grams*(metersPerHundred/100);
  } else {
    // Режим 2: через плотность + эмпирический коэффициент K
    const stPerCm=stitches/sampleSize;
    const rowPerCm=rows/sampleSize;
    const consumptionPerCm2=(1/stPerCm)*(1/rowPerCm)*kFactor*(patternFactor||1.0);
    meters=areaItem*consumptionPerCm2;
    if(metersPerHundred>0)grams=meters/(metersPerHundred/100);
  }
  return{
    grams:Math.round(grams*(1+margin/100)),
    meters:Math.round(meters*(1+margin/100)),
  };
}

// ── Кроссбраузерный roundRect для canvas ─────────────────────────────────────
function canvasRoundRect(ctx, x, y, w, h, r) {
  ctx.beginPath();
  ctx.moveTo(x + r, y);
  ctx.lineTo(x + w - r, y);
  ctx.quadraticCurveTo(x + w, y, x + w, y + r);
  ctx.lineTo(x + w, y + h - r);
  ctx.quadraticCurveTo(x + w, y + h, x + w - r, y + h);
  ctx.lineTo(x + r, y + h);
  ctx.quadraticCurveTo(x, y + h, x, y + h - r);
  ctx.lineTo(x, y + r);
  ctx.quadraticCurveTo(x, y, x + r, y);
  ctx.closePath();
}

// ── Export project card as PNG ────────────────────────────────────────────────
async function exportProjectCard(project){
  const W=1080,H=1080;
  const canvas=document.createElement("canvas");canvas.width=W;canvas.height=H;
  const ctx=canvas.getContext("2d");
  const grd=ctx.createLinearGradient(0,0,W,H);
  grd.addColorStop(0,"#0A0F1A");grd.addColorStop(1,"#1B3A6B");
  ctx.fillStyle=grd;ctx.fillRect(0,0,W,H);
  ctx.beginPath();ctx.arc(880,200,280,0,Math.PI*2);
  ctx.fillStyle="rgba(27,174,200,0.1)";ctx.fill();
  if(project.resultPhoto||project.inspoPhoto){
    await new Promise(res=>{
      const img=new Image();img.onload=()=>{
        ctx.save();ctx.beginPath();
        if(ctx.roundRect)canvasRoundRect(ctx, 60,60,480,480,28);
        else ctx.rect(60,60,480,480);
        ctx.clip();ctx.drawImage(img,60,60,480,480);ctx.restore();res();
      };img.onerror=res;img.src=project.resultPhoto||project.inspoPhoto;
    });
  } else {
    ctx.fillStyle="rgba(27,174,200,0.12)";
    if(ctx.roundRect)canvasRoundRect(ctx, 60,60,480,480,28);else ctx.rect(60,60,480,480);
    ctx.fill();
    ctx.font="100px serif";ctx.textAlign="center";ctx.fillText("🧶",300,360);
  }
  const done=(project.steps||[]).filter(s=>s.done).length;
  const total=(project.steps||[]).length||1;
  const pct=Math.round(done/total*100);
  const cx=800,cy=310,rad=150;
  ctx.strokeStyle="rgba(255,255,255,0.08)";ctx.lineWidth=16;
  ctx.beginPath();ctx.arc(cx,cy,rad,-Math.PI/2,Math.PI*1.5);ctx.stroke();
  ctx.strokeStyle=TEAL;ctx.lineWidth=16;ctx.lineCap="round";
  ctx.beginPath();ctx.arc(cx,cy,rad,-Math.PI/2,((pct/100)*2-0.5)*Math.PI);ctx.stroke();
  ctx.fillStyle="#fff";ctx.font="bold 68px sans-serif";ctx.textAlign="center";
  ctx.fillText(pct+"%",cx,cy+22);
  ctx.fillStyle="rgba(255,255,255,0.45)";ctx.font="26px sans-serif";
  ctx.fillText("выполнено",cx,cy+58);
  ctx.fillStyle="#fff";ctx.textAlign="left";ctx.font="bold 60px sans-serif";
  const nm=project.name.length>20?project.name.slice(0,20)+"…":project.name;
  ctx.fillText(nm,60,630);
  ctx.fillStyle="rgba(255,255,255,0.55)";ctx.font="34px sans-serif";
  ctx.fillText(project.type+" · "+project.size,60,685);
  (project.yarns||[]).slice(0,6).forEach((y,i)=>{
    ctx.beginPath();ctx.arc(60+i*52,750,18,0,Math.PI*2);
    ctx.fillStyle=y.color;ctx.fill();
    ctx.strokeStyle="rgba(255,255,255,0.2)";ctx.lineWidth=2;ctx.stroke();
  });
  ctx.fillStyle="rgba(255,255,255,0.08)";
  if(ctx.roundRect)canvasRoundRect(ctx, 60,800,W-120,10,5);else ctx.rect(60,800,W-120,10);
  ctx.fill();
  ctx.fillStyle=TEAL;
  if(ctx.roundRect)canvasRoundRect(ctx, 60,800,(W-120)*(pct/100),10,5);else ctx.rect(60,800,(W-120)*(pct/100),10);
  ctx.fill();
  ctx.fillStyle="rgba(255,255,255,0.35)";ctx.font="24px sans-serif";ctx.textAlign="right";
  ctx.fillText("Твоё хобби · tvoe-hobby.ru",W-60,H-28);
  const link=document.createElement("a");
  link.download=(project.name.replace(/\s+/g,"_")||"project")+".png";
  link.href=canvas.toDataURL("image/png");link.click();
}


